const body = $input.first().json.body || $input.first().json;
const kbId = body.kbId;
const sourceUrl = body.sourceUrl;
const sourceBranch = body.sourceBranch || 'main';
const sourcePath = body.sourcePath || '';
const difyDatasetId = body.difyDatasetId;
const difyApiUrl = body.difyApiUrl || 'http://dify-api:5001';
const difyApiKey = body.difyApiKey || '';
const syncJobId = body.syncJobId;
const progressCallbackUrl = body.progressCallbackUrl;
const progressCallbackToken = body.progressCallbackToken || '';
const sourceToken = body.sourceToken || '';

if (!kbId || !sourceUrl || !difyDatasetId || !syncJobId || !difyApiKey) {
  throw new Error('Missing required sync parameters');
}

const match = sourceUrl.match(/github\.com\/([^/]+)\/([^/]+)/);
if (!match) throw new Error('Invalid GitHub URL: ' + sourceUrl);
const owner = match[1];
const repo = match[2].replace(/\.git$/, '');

return [{ json: {
  kbId, owner, repo,
  branch: sourceBranch,
  path: sourcePath,
  difyDatasetId, difyApiUrl, difyApiKey,
  syncJobId, progressCallbackUrl, progressCallbackToken, sourceToken,
  syncStartedAt: new Date().toISOString()
} }];

const items = $input.all();
const params = $('Parse Sync Params').first().json;
if (params.progressCallbackUrl) {
  const headers = { 'Content-Type': 'application/json' };
  if (params.progressCallbackToken) headers['X-Rag-Sync-Token'] = params.progressCallbackToken;
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: params.progressCallbackUrl,
      headers,
      body: {
        syncJobId: params.syncJobId,
        status: 'running',
        filesProcessed: 0,
        filesTotal: 0,
        step: {
          task: 'Fetch File Tree',
          stepName: 'fetch_file_tree',
          status: 'running',
          startedAt: params.syncStartedAt,
        },
        logMessage:           'Sync started for KB ' + params.kbId,
      },
      json: true,
    });
  } catch {}
}
return items;

const tree = $input.first().json.tree || [];
const params = $('Parse Sync Params').first().json;
const basePath = (params.path || '').replace(/\/+$/, '');

const TEXT_EXTS = new Set(['md','markdown','txt','html','htm','xml','csv']);
const files = tree.filter(item => {
  if (item.type !== 'blob') return false;
  const ext = (item.path.split('.').pop() || '').toLowerCase();
  if (!TEXT_EXTS.has(ext)) return false;
  if (basePath && !item.path.startsWith(basePath + '/') && item.path !== basePath) return false;
  return true;
}).slice(0, 500);

if (files.length === 0) throw new Error('No supported files found in repository path');

return files.map((item, index) => ({ json: {
  ...params,
  filePath: item.path,
  fileSha: item.sha,
  fileExt: (item.path.split('.').pop() || '').toLowerCase(),
  fileIndex: index + 1,
  totalFiles: files.length
} }));

const items = $input.all();
const params = $('Parse Sync Params').first().json;
if (params.progressCallbackUrl) {
  const headers = { 'Content-Type': 'application/json' };
  if (params.progressCallbackToken) headers['X-Rag-Sync-Token'] = params.progressCallbackToken;
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: params.progressCallbackUrl,
      headers,
      body: {
        syncJobId: params.syncJobId,
        status: 'running',
        filesTotal: items.length,
        filesProcessed: 0,
        step: {
          task: 'Fetch File Tree',
          stepName: 'fetch_file_tree',
          status: 'completed',
          completedAt: new Date().toISOString(),
          message: 'Found ' + items.length + ' supported files',
        },
        logMessage: 'File tree ready: ' + items.length + ' files to upload',
      },
      json: true,
    });
  } catch {}
}
return items;

const TEXT_EXTS = new Set(['md','markdown','txt','html','htm','xml','csv']);
const items = $input.all();
const results = [];
for (let itemIndex = 0; itemIndex < items.length; itemIndex++) {
  const item = items[itemIndex];
  const { filePath, fileExt, difyApiUrl, difyDatasetId, difyApiKey } = item.json;
  const binaryFile = item.binary && item.binary.fileData ? item.binary.fileData : null;
  let docId = null, difyBatch = null, uploadError = null;
  try {
    if (!TEXT_EXTS.has(fileExt)) {
      uploadError = 'Unsupported file extension for current sync workflow: ' + fileExt;
    } else if (!binaryFile) {
      uploadError = 'Fetch File Content did not return fileData for ' + filePath;
    } else {
      const fileBuffer = await this.helpers.getBinaryDataBuffer(itemIndex, 'fileData');
      const text = fileBuffer.toString('utf8');
      const response = await this.helpers.httpRequest({
        method: 'POST',
        url: difyApiUrl + '/v1/datasets/' + difyDatasetId + '/document/create_by_text',
        headers: {
          Authorization: 'Bearer ' + difyApiKey,
          'Content-Type': 'application/json',
        },
        body: {
          name: filePath,
          text,
          indexing_technique: 'high_quality',
          process_rule: {
            mode: 'custom',
            rules: {
              pre_processing_rules: [
                { id: 'remove_extra_spaces', enabled: true },
                { id: 'remove_urls_emails', enabled: false },
              ],
              segmentation: { separator: '\n\n', max_tokens: 1000, chunk_overlap: 200 },
            },
          },
        },
        json: true,
        returnFullResponse: true,
      });
      const payload = response.body ?? response;
      docId = payload.document?.id ?? null;
      difyBatch = payload.batch ?? null;
      if (!docId || !difyBatch) {
        uploadError = payload.message || 'Dify did not return a document id and batch';
      }
    }
  } catch (e) {
    uploadError = e?.response?.body?.message || e?.message || String(e);
  }
  results.push({ json: { ...item.json, difyDocId: docId, difyBatch, uploadError, uploadMethod: 'text' } });
}
return results;

const items = $input.all();
const params = $('Parse Sync Params').first().json;
for (const item of items) {
  if (!params.progressCallbackUrl) continue;
  const headers = { 'Content-Type': 'application/json' };
  if (params.progressCallbackToken) headers['X-Rag-Sync-Token'] = params.progressCallbackToken;
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: params.progressCallbackUrl,
      headers,
      body: {
        syncJobId: params.syncJobId,
        status: 'running',
        filesProcessed: item.json.fileIndex,
        filesTotal: item.json.totalFiles,
        chunksProcessed: item.json.fileIndex,
        step: {
          task: 'Upload Files',
          stepName: 'upload_files',
          status: item.json.uploadError ? 'failed' : 'running',
          message: item.json.fileIndex + '/' + item.json.totalFiles + ' processed',
          errorMessage: item.json.uploadError || undefined,
        },
        logMessage: 'Processed ' + item.json.filePath + (item.json.uploadError ? ' | ERROR: ' + item.json.uploadError : ''),
        logSeverity: item.json.uploadError ? 'ERROR' : 'INFO',
      },
      json: true,
    });
  } catch {}
}
return items;

const items = $input.all();
const documentRefs = items
  .filter(item => item.json.difyDocId != null && item.json.difyBatch != null)
  .map(item => ({
    filePath: item.json.filePath,
    difyDocId: item.json.difyDocId,
    batchId: item.json.difyBatch,
  }));
const docIds = documentRefs.map(ref => ref.difyDocId);
const batchIds = documentRefs.map(ref => ref.batchId);
const uploadErrors = items
  .filter(item => item.json.uploadError)
  .map(item => ({ filePath: item.json.filePath, error: item.json.uploadError }));
const params = $('Parse Sync Params').first().json;
const totalFiles = items.reduce((max, item) => Math.max(max, Number(item.json.totalFiles || 0)), 0);
return [{ json: { docIds, batchIds, documentRefs, uploadErrors, params, uploadedCount: docIds.length, totalFiles } }];

const items = $input.all();
const summary = $input.first().json;
const params = $('Parse Sync Params').first().json;
if (params.progressCallbackUrl) {
  const headers = { 'Content-Type': 'application/json' };
  if (params.progressCallbackToken) headers['X-Rag-Sync-Token'] = params.progressCallbackToken;
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: params.progressCallbackUrl,
      headers,
      body: {
        syncJobId: params.syncJobId,
        status: summary.uploadErrors.length ? 'failed' : 'running',
        filesProcessed: summary.totalFiles,
        filesTotal: summary.totalFiles,
        step: {
          task: 'Upload Files',
          stepName: 'upload_files',
          status: summary.uploadErrors.length ? 'failed' : 'completed',
          completedAt: new Date().toISOString(),
          message: summary.uploadedCount + ' files uploaded',
          errorMessage: summary.uploadErrors.length ? summary.uploadErrors[0].filePath + ': ' + summary.uploadErrors[0].error : undefined,
        },
        errorMessage: summary.uploadErrors.length ? summary.uploadErrors[0].filePath + ': ' + summary.uploadErrors[0].error : undefined,
        logMessage: summary.uploadErrors.length
          ? 'Upload failed for ' + summary.uploadErrors.length + ' files'
          : 'All ' + summary.uploadedCount + ' files uploaded to Dify. Starting indexing poll...',
        logSeverity: summary.uploadErrors.length ? 'ERROR' : 'INFO',
      },
      json: true,
    });
  } catch {}
}
return items;

const items = $input.all();
const summary = $input.first().json;
const params = $('Parse Sync Params').first().json;
if (params.progressCallbackUrl && summary.batchIds.length > 0) {
  const headers = { 'Content-Type': 'application/json' };
  if (params.progressCallbackToken) headers['X-Rag-Sync-Token'] = params.progressCallbackToken;
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: params.progressCallbackUrl,
      headers,
      body: {
        syncJobId: params.syncJobId,
        status: 'running',
        step: {
          task: 'Dify Indexing',
          stepName: 'dify_indexing',
          status: 'running',
          startedAt: new Date().toISOString(),
          message: 'Indexing ' + summary.batchIds.length + ' files',
        },
        logMessage: 'Indexing ' + summary.batchIds.length + ' files in Dify...',
      },
      json: true,
    });
  } catch {}
}
return items;

const { docIds, batchIds, documentRefs, params, uploadErrors, totalFiles, uploadedCount } = $input.first().json;
const refsByBatch = Object.fromEntries((documentRefs || []).map(ref => [ref.batchId, ref]));
const retryableError = (error) => {
  const normalized = String(error || '').toLowerCase();
  return ['too many requests', 'rate limit', 'ratelimit', '429', 'timeout', 'timed out', 'temporary', 'temporarily', 'embedding', 'upstream', 'unavailable', 'overloaded', 'try again'].some(token => normalized.includes(token));
};
if (!batchIds.length) {
  return [{ json: {
    docIds: [],
    batchIds: [],
    documentRefs: [],
    results: {},
    failedDocuments: [],
    completedCount: 0,
    errorCount: 0,
    timedOut: false,
    uploadErrors: uploadErrors || [],
    finalStatus: uploadErrors && uploadErrors.length ? 'failed' : 'completed',
    params,
    totalFiles,
    uploadedCount,
  } }];
}
const maxAttempts = 24;
const intervalMs = 5000;
const results = {};
const failedByDocId = {};
for (let attempt = 0; attempt < maxAttempts; attempt++) {
  await new Promise(r => setTimeout(r, intervalMs));
  let allDone = true;
  for (const batchId of batchIds) {
    if (results[batchId] === 'completed' || results[batchId] === 'error') continue;
    const ref = refsByBatch[batchId] || {};
    try {
      const data = await this.helpers.httpRequest({
        method: 'GET',
        url: params.difyApiUrl + '/v1/datasets/' + params.difyDatasetId + '/documents/' + batchId + '/indexing-status',
        headers: { Authorization: 'Bearer ' + params.difyApiKey },
        json: true,
      });
      const rows = Array.isArray(data.data) ? data.data : [];
      const statuses = rows.map(item => item.indexing_status).filter(Boolean);
      const erroredRows = rows.filter(item => item.indexing_status === 'error');
      for (const row of erroredRows) {
        const difyDocId = row.id || row.document_id || row.doc_id || ref.difyDocId;
        const error = row.error || row.error_message || row.message || 'Dify indexing failed';
        failedByDocId[difyDocId || batchId] = {
          filePath: ref.filePath || row.name,
          difyDocId,
          batchId,
          indexingStatus: 'error',
          error,
          retryable: retryableError(error),
        };
      }
      const hasError = erroredRows.length > 0 || statuses.includes('error');
      const hasPending = statuses.some(status => !['completed', 'error'].includes(status));
      const status = hasError ? 'error' : (hasPending ? 'indexing' : (statuses.length ? 'completed' : undefined));
      if (status) results[batchId] = status;
      if (status !== 'completed' && status !== 'error') allDone = false;
    } catch (e) {
      allDone = false;
    }
  }
  if (allDone) break;
}
const timedOutBatches = batchIds.filter(batchId => !['completed', 'error'].includes(results[batchId]));
for (const batchId of timedOutBatches) {
  const ref = refsByBatch[batchId] || {};
  failedByDocId[ref.difyDocId || batchId] = {
    filePath: ref.filePath,
    difyDocId: ref.difyDocId,
    batchId,
    indexingStatus: results[batchId] || 'timeout',
    error: 'Indexing timed out',
    retryable: true,
  };
}
const failedDocuments = Object.values(failedByDocId);
const completedCount = Object.values(results).filter(s => s === 'completed').length;
const errorCount = failedDocuments.length;
const timedOut = timedOutBatches.length > 0;
const hasFailures = errorCount > 0 || timedOut || (uploadErrors && uploadErrors.length > 0);
return [{ json: {
  docIds, batchIds, documentRefs, results, failedDocuments, completedCount, errorCount, timedOut,
  uploadErrors: uploadErrors || [],
  finalStatus: hasFailures ? 'failed' : 'completed',
  params,
  totalFiles,
  uploadedCount,
} }];

const items = $input.all();
const summary = $input.first().json;
const params = $('Parse Sync Params').first().json;
const firstUploadError = summary.uploadErrors && summary.uploadErrors.length ? (summary.uploadErrors[0].filePath + ': ' + summary.uploadErrors[0].error) : '';
const failedDocuments = summary.failedDocuments || [];
const firstFailedDoc = failedDocuments.length ? failedDocuments[0] : null;
const failedDocSummary = firstFailedDoc ? ((firstFailedDoc.filePath || firstFailedDoc.difyDocId || 'unknown document') + (firstFailedDoc.error ? ': ' + firstFailedDoc.error : '')) : '';
const finalError = firstUploadError || (failedDocuments.length > 0 ? (failedDocuments.length + ' docs failed indexing: ' + failedDocSummary) : (summary.timedOut ? 'Indexing timed out' : ''));
if (params.progressCallbackUrl) {
  const headers = { 'Content-Type': 'application/json' };
  if (params.progressCallbackToken) headers['X-Rag-Sync-Token'] = params.progressCallbackToken;
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: params.progressCallbackUrl,
      headers,
      body: {
        syncJobId: params.syncJobId,
        status: summary.finalStatus,
        filesProcessed: summary.totalFiles,
        filesTotal: summary.totalFiles,
        chunksProcessed: summary.completedCount,
        errorMessage: finalError || undefined,
        step: summary.uploadErrors && summary.uploadErrors.length ? {
          task: 'Upload Files',
          stepName: 'upload_files',
          status: 'failed',
          completedAt: new Date().toISOString(),
          message: 'Upload failed for ' + summary.uploadErrors.length + ' files',
          errorMessage: firstUploadError,
        } : {
          task: 'Dify Indexing',
          stepName: 'dify_indexing',
          status: summary.finalStatus,
          completedAt: new Date().toISOString(),
          message: summary.finalStatus === 'completed'
            ? summary.totalFiles + ' / ' + summary.totalFiles + ' indexed'
            : summary.completedCount + ' indexed, ' + failedDocuments.length + ' errors',
          errorMessage: finalError || undefined,
          failedDocuments,
        },
        logMessage: finalError ? ('Sync failed: ' + finalError) : ('Sync complete: ' + summary.completedCount + '/' + summary.totalFiles + ' docs indexed'),
        logSeverity: summary.finalStatus === 'failed' ? 'ERROR' : 'INFO',
      },
      json: true,
    });
  } catch {}
}
return items;
